function sendPcm(seq, part, flags) {
    const h = Buffer.alloc(8);
    h.writeUInt32LE(seq >>> 0, 0);
    h.writeUInt16LE(part.length & 0xFFFF, 4);
    h.writeUInt16LE(flags & 0xFFFF, 6);
    node.send({
        topic: `${BASE}/pcm`,
        qos: QOS_PCM,
        payload: Buffer.concat([h, part])
    });
}

