    const part = pcm.subarray(off, Math.min(off + CHUNK_BYTES, pcm.length));
    const isLast = (off + CHUNK_BYTES) >= pcm.length;
    const flags = isLast ? 0x0002 : 0x0000; // 例: bit1=last

