// 例:
// ".m5-8 test"     -> ".M5-8 test"
// ".m5-8.fh test"  -> ".M5-8.fh test"
function replaceHeadIdWithHitKey(line, hitKey) {
    return String(line).replace(/^\.([^. \t]+)(?=\.|\s|$)/, "." + String(hitKey));
}

// idmap のキーを大小区別せず探して IP を引く
function resolveIpById(idRaw) {
    const idLower = norm(idRaw);
    let hitKey = null;
    for (const k of Object.keys(idmap)) {
        if (String(k).toLowerCase() === idLower) {
            hitKey = k;
            break;
        }
    }
    const ip = hitKey ? (idmap[hitKey]?.IP ?? null) : null;
    return { hitKey, ip };
}

