    // IDは ".<id>(.<subcmd>...)" の <id> 部分
    const idRaw = cmd.slice(1).split(".")[0];

    const { hitKey, ip } = resolveIpById(idRaw);
    if (!ip) {
        // IP不明：以降も処理しない（break相当）
        stopAll();
        return;
    }

    // publish用に、先頭のID表記を idmap の実キー表記へ揃える
    const normalizedLine = replaceHeadIdWithHitKey(line, hitKey);

    // ---- ここから「この1行の3段送信」 ----
