    setTimeout(() => {
        const payload2 = cmdSpaceToNewline(normalizedLine);
        node.status({ text: payload2 });

        node.send({
            topic: `${ROOT}/${guild_id}/${channel_id}`,
            payload: payload2,
            status: "投稿しました",
            id: hitKey,
            ip
        });

        // 次の行へ
        setTimeout(processOneLine, 0);
    }, 500);
}

